function solve(landStartTime, landDuration, waterStartTime, waterDuration) {
    // Precompute all possible end times for land and water attractions
    const landEndTimes = [];
    for (let i = 0; i < landStartTime.length; i++) {
        // The land attraction can start at its earliest time or later
        // We choose the earliest possible start time to minimize the end time
        const startTime = landStartTime[i];
        const endTime = startTime + landDuration[i];
        landEndTimes.push(endTime);
    }

    const waterEndTimes = [];
    for (let j = 0; j < waterStartTime.length; j++) {
        // The water attraction can start at its earliest time or later
        // We choose the earliest possible start time to minimize the end time
        const startTime = waterStartTime[j];
        const endTime = startTime + waterDuration[j];
        waterEndTimes.push(endTime);
    }

    // Try all combinations of one land and one water attraction
    let minEndTime = Infinity;
    for (let i = 0; i < landEndTimes.length; i++) {
        for (let j = 0; j < waterEndTimes.length; j++) {
            // Calculate the earliest possible end time for this combination
            // If the land ends before the water starts, the water starts after the land ends
            // If the water ends before the land starts, the land starts after the water ends
            // Otherwise, they can be done in sequence
            const landEnd = landEndTimes[i];
            const waterEnd = waterEndTimes[j];

            // Calculate the earliest time the second attraction can start
            const startSecond = Math.max(landEnd, waterEnd);
            const endSecond = startSecond + Math.max(landEnd, waterEnd);

            minEndTime = Math.min(minEndTime, endSecond);
        }
    }

    return minEndTime;
}

